import { Boxes, Gauge, Megaphone, ShoppingCart, Wrench, Zap } from "lucide-react"

const SERVICES = [
  {
    icon: Zap,
    title: "Landing pages",
    body: "One page. One job. Conversion or bust.",
    big: true,
  },
  { icon: ShoppingCart, title: "E-commerce", body: "Stores that load before the doubt kicks in." },
  { icon: Gauge, title: "Performance", body: "Sub-second or we keep working." },
  { icon: Megaphone, title: "SEO", body: "Rankings you can screenshot." },
  { icon: Boxes, title: "Design systems", body: "Components, not chaos." },
  {
    icon: Wrench,
    title: "Retainers",
    body: "A crew on call. Fixed price, no surprise invoices, cancel monthly.",
    big: true,
  },
]

/**
 * Brutal bento — heavy bordered grid where every cell inverts to black
 * on hover and the icon picks up the accent.
 */
export function BentoBrutal() {
  return (
    <section className="border-y-4 border-foreground bg-background px-5 py-20 text-foreground sm:px-8">
      <div className="mx-auto max-w-6xl">
        <h2 className="mb-3 text-[clamp(2.25rem,6vw,4.5rem)] font-black leading-none tracking-tighter uppercase">
          What we <span className="bg-accent px-2">do</span>
        </h2>
        <p className="mb-12 max-w-md font-mono text-sm">
          Six things. Done loudly, shipped quietly, billed honestly.
        </p>

        <div className="grid border-2 border-foreground md:grid-cols-4">
          {SERVICES.map((s) => (
            <article
              key={s.title}
              className={`group -mt-px -ml-px border-2 border-foreground bg-background p-6 transition-colors duration-150 hover:bg-foreground hover:text-background ${
                s.big ? "md:col-span-2 md:row-span-1" : ""
              }`}
            >
              <s.icon className="size-8 transition-colors group-hover:text-accent" strokeWidth={2.5} />
              <h3 className="mt-10 text-xl font-black tracking-tight uppercase">
                {s.title}
              </h3>
              <p className="mt-2 font-mono text-sm leading-snug opacity-80">
                {s.body}
              </p>
            </article>
          ))}
        </div>
      </div>
    </section>
  )
}

"use client"

import * as React from "react"
import Link from "next/link"
import { ArrowRight, Menu, X } from "lucide-react"

const NAV = [
  { label: "Work", href: "#work" },
  { label: "About", href: "#about" },
  { label: "Process", href: "#process" },
  { label: "Contact", href: "#contact" },
]

/**
 * Brutal header — sticky bar with thick borders, boxed nav cells that
 * invert on hover, and a hard-shadow CTA.
 */
export function HeaderBrutal() {
  const [open, setOpen] = React.useState(false)

  return (
    <header className="sticky top-0 z-50 border-b-4 border-foreground bg-background text-foreground">
      <div className="flex items-stretch justify-between">
        <Link
          href="#"
          className="flex items-center gap-2 px-5 py-4 text-xl font-black tracking-tighter uppercase"
        >
          <span className="grid size-7 place-items-center bg-foreground font-mono text-sm text-background">
            T
          </span>
          Tonne®
        </Link>

        <nav className="hidden items-stretch md:flex">
          {NAV.map((item) => (
            <Link
              key={item.label}
              href={item.href}
              className="flex items-center border-l-2 border-foreground px-6 text-sm font-bold tracking-wide uppercase transition-colors hover:bg-foreground hover:text-background"
            >
              {item.label}
            </Link>
          ))}
          <Link
            href="#quote"
            className="flex items-center gap-2 border-l-2 border-foreground bg-accent px-6 text-sm font-black tracking-wide uppercase text-accent-foreground transition-colors hover:bg-foreground hover:text-background"
          >
            Get a quote
            <ArrowRight className="size-4" />
          </Link>
        </nav>

        <button
          className="flex items-center border-l-2 border-foreground px-5 md:hidden"
          onClick={() => setOpen((v) => !v)}
          aria-label={open ? "Close menu" : "Open menu"}
        >
          {open ? <X className="size-6" /> : <Menu className="size-6" />}
        </button>
      </div>

      {open && (
        <nav className="border-t-2 border-foreground md:hidden">
          {NAV.map((item) => (
            <Link
              key={item.label}
              href={item.href}
              onClick={() => setOpen(false)}
              className="block border-b-2 border-foreground px-5 py-4 text-2xl font-black uppercase hover:bg-foreground hover:text-background"
            >
              {item.label}
            </Link>
          ))}
          <Link
            href="#quote"
            onClick={() => setOpen(false)}
            className="flex items-center justify-between bg-accent px-5 py-4 text-2xl font-black uppercase text-accent-foreground"
          >
            Get a quote
            <ArrowRight className="size-6" />
          </Link>
        </nav>
      )}
    </header>
  )
}
